import json
import requests
from urllib.parse import urlparse

def lambda_handler(event, context):
    # Get the request from the event
    request = event['Records'][0]['cf']['request']
    
    # Extract the X-Enrich-URL header
    enrich_url_header = request.get('headers', {}).get('x-enrich-url')
    
    if enrich_url_header:
        # Decode and get the first URL (assuming only one URL in the header)
        enrich_url = enrich_url_header[0]['value'].decode('utf-8')
        
        try:
            # Make a GET request to the enrich URL
            response = requests.get(enrich_url, timeout=2)
            response.raise_for_status()  # Raise an error for bad responses
            
            # Parse the JSON response
            enrich_data = response.json()
            
            # Add the fetched data as custom headers or modify the request
            if 'headers' not in request:
                request['headers'] = {}
            request['headers']['x-enrich-data'] = [{'key': 'X-Enrich-Data', 'value': json.dumps(enrich_data).encode('utf-8')}]
        
        except requests.RequestException as e:
            # Log the error or handle it appropriately
            print(f"Error fetching enrichment data: {e}")
    
    return request